import { getMetadataRows } from './metadata-formatter';
import { TOOLTIP_STYLES } from './tooltip-styles';
import type {
    TooltipItem,
    TooltipPosition,
    TooltipShowOptions,
} from './types';

export const BZ_TOOLTIP_TAG = 'bz-item-tooltip';
const POSITION_OFFSET = 10;

type PointerPosition = TooltipPosition | MouseEvent | PointerEvent;

const escapeHtml = (value: unknown): string => String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');

const formatDescription = (value: string): string => escapeHtml(value)
    .replace(/&lt;highlight&gt;/gi, '<highlight>')
    .replace(/&lt;\/highlight&gt;/gi, '</highlight>');

const getSafeColor = (value?: string): string => {
    if (!value) return '#f5f5f5';
    return CSS.supports('color', value) ? value : '#f5f5f5';
};

const getPosition = (position: PointerPosition): TooltipPosition => {
    if ('clientX' in position) {
        return { x: position.clientX, y: position.clientY };
    }
    return position;
};

export class BZTooltipElement extends HTMLElement {
    readonly #root: ShadowRoot;
    #item: TooltipItem | null = null;
    #followCursor = true;

    constructor() {
        super();
        this.#root = this.attachShadow({ mode: 'open' });
    }

    connectedCallback(): void {
        this.#render();
    }

    disconnectedCallback(): void {
        window.removeEventListener('pointermove', this.#handlePointerMove);
    }

    show(
        item: TooltipItem,
        position: PointerPosition,
        options: TooltipShowOptions = {},
    ): void {
        this.#item = item;
        this.#followCursor = options.followCursor ?? true;
        this.dataset.rawItemId = item.rawItemId;
        this.#render();
        this.setAttribute('open', '');
        this.move(position);

        window.removeEventListener('pointermove', this.#handlePointerMove);
        if (this.#followCursor) {
            window.addEventListener('pointermove', this.#handlePointerMove);
        }
    }

    hide(): void {
        this.removeAttribute('open');
        window.removeEventListener('pointermove', this.#handlePointerMove);
    }

    move(position: PointerPosition): void {
        const { x: clientX, y: clientY } = getPosition(position);
        const width = this.offsetWidth;
        const height = this.offsetHeight;
        let x = clientX + POSITION_OFFSET;
        let y = clientY + POSITION_OFFSET;

        if (x + width + POSITION_OFFSET > window.innerWidth) {
            x = window.innerWidth - width - POSITION_OFFSET;
        }
        if (y + height + POSITION_OFFSET > window.innerHeight) {
            y = window.innerHeight - height - POSITION_OFFSET;
        }

        x = Math.max(POSITION_OFFSET, x);
        y = Math.max(POSITION_OFFSET, y);
        this.style.transform = `translate(${x}px, ${y}px)`;
    }

    #handlePointerMove = (event: PointerEvent): void => {
        this.move(event);
    };

    #render(): void {
        const item = this.#item;
        if (!item) {
            this.#root.innerHTML = `<style>${TOOLTIP_STYLES}</style>`;
            return;
        }

        const metadataRows = getMetadataRows(item.metadata);
        const description = item.description
            ? `<div class="description">${formatDescription(item.description)}</div>`
            : '';
        const category = item.category
            ? `<div class="category">${escapeHtml(item.category)}</div>`
            : '';
        const background = item.backgroundUrl
            ? `<img class="background" src="${escapeHtml(item.backgroundUrl)}" alt="">`
            : `<img class="glow" src="${escapeHtml(item.imageUrl)}" alt="">`;
        const weight = item.weight !== undefined
            ? this.#renderRow('น้ำหนัก', `${(item.weight * item.count).toFixed(1)} kg`)
            : '';
        const metadata = metadataRows.length > 0
            ? `
                <div class="metadata-title">ข้อมูลเพิ่มเติม</div>
                ${metadataRows.map((row) => this.#renderRow(row.label, row.value)).join('')}
            `
            : '';
        const count = `${item.count.toLocaleString()}${
            item.limit !== undefined ? ` / ${item.limit.toLocaleString()}` : ''
        }`;

        this.#root.innerHTML = `
            <style>${TOOLTIP_STYLES}</style>
            <article class="tooltip" role="tooltip">
                ${background}
                <header class="header">
                    <div class="title-wrap">
                        <div class="title" style="color: ${escapeHtml(getSafeColor(item.labelColor))}">
                            ${escapeHtml(item.label)}
                        </div>
                        ${category}
                    </div>
                    <img class="item-image" src="${escapeHtml(item.imageUrl)}" alt="${escapeHtml(item.label)}">
                </header>
                <section class="details">
                    ${description}
                    ${this.#renderRow('จำนวน', count)}
                    ${weight}
                    ${metadata}
                </section>
            </article>
        `;
    }

    #renderRow(label: string, value: string): string {
        return `
            <div class="row">
                <span class="row-label">${escapeHtml(label)}</span>
                <span class="row-value">${escapeHtml(value)}</span>
            </div>
        `;
    }
}

export const defineBZTooltip = (): void => {
    if (!customElements.get(BZ_TOOLTIP_TAG)) {
        customElements.define(BZ_TOOLTIP_TAG, BZTooltipElement);
    }
};
