import { parseRawItemId } from './inventory-helpers';
import type { Item, ItemConfig, Items } from './types';

export type InventoryStats = {
    totalWeight: number;
    slots: number;
};

export const calculateInventoryStats = (
    items: Items<Item>,
    itemsConfig: Items<ItemConfig>,
): InventoryStats => {
    let totalWeight = 0;
    const slots = Object.keys(items).length;

    for (const [rawId, item] of Object.entries(items)) {
        const baseId = parseRawItemId(rawId).itemId;
        const weight = itemsConfig[baseId]?.weight ?? 0;
        totalWeight += weight * (item.count ?? 0);
    }

    return { totalWeight, slots };
};

