import {
    BZ_TOOLTIP_TAG,
    BZTooltipElement,
    defineBZTooltip,
} from './bz-tooltip';
import type {
    TooltipItem,
    TooltipPosition,
    TooltipShowOptions,
} from './types';

export * from './bz-tooltip';
export * from './inventory-helpers';
export * from './inventory-stats';
export * from './metadata-formatter';
export * from './types';

let defaultTooltip: BZTooltipElement | null = null;

const getDefaultTooltip = (): BZTooltipElement => {
    if (defaultTooltip?.isConnected) return defaultTooltip;

    defineBZTooltip();
    defaultTooltip = document.createElement(BZ_TOOLTIP_TAG) as BZTooltipElement;
    (document.body || document.documentElement).append(defaultTooltip);
    return defaultTooltip;
};

export const showTooltip = (
    item: TooltipItem,
    position: TooltipPosition | MouseEvent | PointerEvent,
    options?: TooltipShowOptions,
): BZTooltipElement => {
    const tooltip = getDefaultTooltip();
    tooltip.show(item, position, options);
    return tooltip;
};

export const hideTooltip = (): void => {
    defaultTooltip?.hide();
};

export type BindTooltipOptions = TooltipShowOptions & {
    delay?: number;
    hideOnPointerDown?: boolean;
};

export const bindTooltip = (
    target: Element,
    getItem: (event: PointerEvent) => TooltipItem | null | undefined,
    options: BindTooltipOptions = {},
): (() => void) => {
    let timer: ReturnType<typeof setTimeout> | undefined;

    const clearTimer = (): void => {
        if (timer !== undefined) clearTimeout(timer);
        timer = undefined;
    };

    const handleEnter = (event: Event): void => {
        const pointerEvent = event as PointerEvent;
        const item = getItem(pointerEvent);
        if (!item) return;

        clearTimer();
        const open = (): void => {
            showTooltip(item, pointerEvent, options);
        };

        if ((options.delay ?? 0) > 0) {
            timer = setTimeout(open, options.delay);
        } else {
            open();
        }
    };

    const handleLeave = (): void => {
        clearTimer();
        hideTooltip();
    };

    const handlePointerDown = (): void => {
        if (options.hideOnPointerDown ?? true) handleLeave();
    };

    target.addEventListener('pointerenter', handleEnter);
    target.addEventListener('pointerleave', handleLeave);
    target.addEventListener('pointerdown', handlePointerDown);

    return () => {
        clearTimer();
        target.removeEventListener('pointerenter', handleEnter);
        target.removeEventListener('pointerleave', handleLeave);
        target.removeEventListener('pointerdown', handlePointerDown);
    };
};

export const BZ_TOOLTIP_TRIGGER_TAG = 'bz-tooltip-trigger';

export class BZTooltipTriggerElement extends HTMLElement {
    #item: TooltipItem | null = null;
    #cleanup: (() => void) | null = null;
    #options: BindTooltipOptions = {
        followCursor: true,
        hideOnPointerDown: true,
        delay: 0,
    };

    get item(): TooltipItem | null {
        return this.#item;
    }

    set item(value: TooltipItem | null) {
        this.#item = value;
    }

    get delay(): number {
        return this.#options.delay ?? 0;
    }

    set delay(value: number) {
        this.#options.delay = Number.isFinite(value) ? Math.max(0, value) : 0;
    }

    get followCursor(): boolean {
        return this.#options.followCursor ?? true;
    }

    set followCursor(value: boolean) {
        this.#options.followCursor = value;
    }

    connectedCallback(): void {
        if (!this.style.display) this.style.display = 'contents';
        this.#cleanup?.();
        this.#cleanup = bindTooltip(this, () => this.#item, this.#options);
    }

    disconnectedCallback(): void {
        this.#cleanup?.();
        this.#cleanup = null;
    }
}

export const defineBZTooltipTrigger = (): void => {
    if (!customElements.get(BZ_TOOLTIP_TRIGGER_TAG)) {
        customElements.define(BZ_TOOLTIP_TRIGGER_TAG, BZTooltipTriggerElement);
    }
};

declare global {
    interface HTMLElementTagNameMap {
        'bz-tooltip-trigger': BZTooltipTriggerElement;
    }
}

if (typeof window !== 'undefined' && 'customElements' in window) {
    defineBZTooltip();
    defineBZTooltipTrigger();
}

